(window.webpackJsonp=window.webpackJsonp||[]).push([[326],{953:function(n,e){n.exports="\x3c!-- \ntitle: 14-弹性布局\nsort: \n--\x3e \n\n> `display: flex;`\n\n## 父容器\n\n```scss\n// 排列反向\nflex-direction: row | row-reverse | column | column-reverse;\n// 换行\nflex-wrap: nowrap | wrap | wrap-reverse;\n// 合并前两个\nflex-flow: column wrap;\n// 水平对齐\njustify-content: \n//\t开头\t\t结尾\t\t中心\nflex-start | flex-end | center | \n//\t两头\t\t中心\t\t等距\nspace-between | space-around | space-evenly \n// 垂直对齐\nalign-items: \n// 拉伸\t\t顶部\t\t\t底部\t\t中心\nstretch | flex-start | flex-end | center | \nbaseline\t// 中心线\n// 多行对齐\nalign-content:\nstretch | flex-start | flex-end | center | \nspace-between | space-around | space-evenly | baseline \n```\n\n## 子项目\n\n```scss\norder: \t\t\t// 顺序\nflex-grow:\t\t// 拉伸比例\nflex-shrink: \t// 收缩比率\nflex-basis:\t\t// 基本宽度\nflex:\t\t\t// 前三者和\n// 子项目对齐方式\nalign-self：\nauto | flex-start | flex-end | center | stretch | baseline\n```\n\n![123](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2021/20210409202913.png)"}}]);